import React, { useState } from 'react';
import { formatDate } from '../../data/bookingStore.js';
import ConfirmModal from './ConfirmModal.jsx';
import styles from '../../styles/admin/BookingsTable.module.css';

const STATUS_COLORS = {
  confirmed: styles.statusConfirmed,
  pending:   styles.statusPending,
};

const IconEdit = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="15" height="15" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/>
    <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/>
  </svg>
);

const IconTrash = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="15" height="15" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="3 6 5 6 21 6"/>
    <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>
    <path d="M10 11v6M14 11v6"/>
    <path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/>
  </svg>
);

const IconMessenger = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="15" height="15" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
  </svg>
);

const computeDiff = function(checkIn, checkOut) {
  if (!checkIn || !checkOut) return 0;
  return Math.round(
    (new Date(checkOut + 'T00:00:00') - new Date(checkIn + 'T00:00:00')) / 86400000
  );
};

const getNightsDisplay = function(b) {
  var n = computeDiff(b.checkIn, b.checkOut);
  if (n <= 0) n = (b.nights && b.nights > 0) ? b.nights : 0;
  if (b.bookingType === 'day-use') {
    return n > 1 ? (n + 'D') : 'Day';
  }
  return n > 0 ? (n + 'N') : '-';
};

const MessengerLink = function(props) {
  if (!props.url) return null;
  return (
    <a href={props.url} target="_blank" rel="noopener noreferrer" className={props.className} title={props.label || 'Open Messenger'}>
      {props.label ? props.label : <IconMessenger />}
    </a>
  );
};

const EditModal = function(props) {
  var booking = props.booking;
  var onSave  = props.onSave;
  var onClose = props.onClose;

  const [form, setForm] = useState({
    guestName:       booking.guestName       || '',
    guestContact:    booking.guestContact    || '',
    checkIn:         booking.checkIn         || '',
    checkOut:        booking.checkOut        || '',
    guests:          booking.guests          || 1,
    total:           booking.total           || 0,
    paid:            booking.paid            || false,
    specialRequests: booking.specialRequests || '',
  });
  const [errors, setErrors] = useState({});

  var set = function(key, val) {
    setForm(function(prev) { return Object.assign({}, prev, { [key]: val }); });
  };

  var validate = function() {
    var e = {};
    if (!form.guestName.trim()) e.guestName = 'Name is required.';
    if (!form.checkIn)          e.checkIn   = 'Check-in date is required.';
    if (form.checkOut && form.checkOut < form.checkIn) e.checkOut = 'Check-out must be after check-in.';
    if (form.guests < 1)        e.guests    = 'At least 1 guest.';
    if (form.total < 0)         e.total     = 'Total cannot be negative.';
    return e;
  };

  var handleSave = function() {
    var e = validate();
    if (Object.keys(e).length) { setErrors(e); return; }
    var nights = computeDiff(form.checkIn, form.checkOut);
    if (nights < 0) nights = 0;
    onSave(Object.assign({}, booking, form, {
      guests: Number(form.guests),
      total:  Number(form.total),
      nights: nights,
    }));
  };

  return (
    <div className={styles.editOverlay} onClick={onClose}>
      <div className={styles.editModal} onClick={function(e) { e.stopPropagation(); }}>
        <div className={styles.editHeader}>
          <h2 className={styles.editTitle}>Edit Booking</h2>
          <span className={styles.editRef}>{booking.id}</span>
        </div>

        <div className={styles.editBody}>
          <div className={styles.editField}>
            <label className={styles.editLabel}>Guest Name</label>
            <input
              className={styles.editInput + (errors.guestName ? ' ' + styles.inputError : '')}
              value={form.guestName}
              onChange={function(e) { set('guestName', e.target.value); }}
            />
            {errors.guestName && <span className={styles.editError}>{errors.guestName}</span>}
          </div>

          <div className={styles.editField}>
            <label className={styles.editLabel}>Contact / Messenger URL</label>
            <input
              className={styles.editInput}
              value={form.guestContact}
              onChange={function(e) { set('guestContact', e.target.value); }}
            />
          </div>

          <div className={styles.editRow}>
            <div className={styles.editField}>
              <label className={styles.editLabel}>Check-in</label>
              <input
                type="date"
                className={styles.editInput + (errors.checkIn ? ' ' + styles.inputError : '')}
                value={form.checkIn}
                onChange={function(e) { set('checkIn', e.target.value); }}
              />
              {errors.checkIn && <span className={styles.editError}>{errors.checkIn}</span>}
            </div>
            <div className={styles.editField}>
              <label className={styles.editLabel}>Check-out / Last Day</label>
              <input
                type="date"
                className={styles.editInput + (errors.checkOut ? ' ' + styles.inputError : '')}
                value={form.checkOut}
                onChange={function(e) { set('checkOut', e.target.value); }}
              />
              {errors.checkOut && <span className={styles.editError}>{errors.checkOut}</span>}
            </div>
          </div>

          <div className={styles.editRow}>
            <div className={styles.editField}>
              <label className={styles.editLabel}>Guests (pax)</label>
              <input
                type="number"
                min="1"
                className={styles.editInput + (errors.guests ? ' ' + styles.inputError : '')}
                value={form.guests}
                onChange={function(e) { set('guests', e.target.value); }}
              />
              {errors.guests && <span className={styles.editError}>{errors.guests}</span>}
            </div>
            <div className={styles.editField}>
              <label className={styles.editLabel}>Total (PHP)</label>
              <input
                type="number"
                min="0"
                className={styles.editInput + (errors.total ? ' ' + styles.inputError : '')}
                value={form.total}
                onChange={function(e) { set('total', e.target.value); }}
              />
              {errors.total && <span className={styles.editError}>{errors.total}</span>}
            </div>
          </div>

          <div className={styles.editField}>
            <label className={styles.editLabel}>Payment Status</label>
            <div className={styles.editToggleRow}>
              <button type="button"
                className={styles.editToggleBtn + (form.paid ? ' ' + styles.togglePaid : '')}
                onClick={function() { set('paid', true); }}>
                Paid
              </button>
              <button type="button"
                className={styles.editToggleBtn + (!form.paid ? ' ' + styles.toggleUnpaid : '')}
                onClick={function() { set('paid', false); }}>
                Unpaid
              </button>
            </div>
          </div>

          <div className={styles.editField}>
            <label className={styles.editLabel}>Special Requests</label>
            <textarea
              className={styles.editTextarea}
              rows={3}
              value={form.specialRequests}
              onChange={function(e) { set('specialRequests', e.target.value); }}
            />
          </div>
        </div>

        <div className={styles.editFooter}>
          <button className={styles.editCancelBtn} onClick={onClose} type="button">Cancel</button>
          <button className={styles.editSaveBtn} onClick={handleSave} type="button">Save Changes</button>
        </div>
      </div>
    </div>
  );
};

const BookingRow = function(props) {
  var b            = props.b;
  var expandedId   = props.expandedId;
  var setExpandedId = props.setExpandedId;
  var onEdit       = props.onEdit;
  var onDelete     = props.onDelete;
  var onPaid       = props.onPaid;

  var contact      = b.guestContact || '';
  var isMessenger  = b.contactMethod === 'messenger';
  var messengerUrl = (isMessenger && contact)
    ? (contact.startsWith('http') ? contact : 'https://' + contact)
    : null;

  var isExpanded = expandedId === b.id;

  var toggleExpand = function() {
    setExpandedId(isExpanded ? null : b.id);
  };

  var typeLabel =
    b.bookingType === 'day-use'   ? '☀️ Day Use'  :
    b.bookingType === 'overnight' ? '🌙 Overnight' :
    b.room ? ((b.room.icon || '') + ' ' + (b.room.name || '')) : '-';

  // ✅ Compute nights/days from actual dates
  var diffN = computeDiff(b.checkIn, b.checkOut);

  // ✅ checkOut display: if diff > 0 use checkOut, else fall back to checkIn
  var checkOutDisplay = (b.checkOut && diffN > 0)
    ? formatDate(b.checkOut)
    : formatDate(b.checkIn);

  return (
    <React.Fragment>
      <tr className={styles.row} onClick={toggleExpand}>

        <td>
          <span className={styles.refCode}>{b.id}</span>
        </td>

        <td>
          <div className={styles.guestName}>{b.guestName}</div>
          <div className={styles.guestEmail}>
            {isMessenger
              ? <span className={styles.messengerTag}>Messenger</span>
              : contact}
          </div>
        </td>

        <td>
          <span className={styles.roomTag}>{typeLabel}</span>
        </td>

        <td className={styles.date}>{formatDate(b.checkIn)}</td>
        <td className={styles.date}>{checkOutDisplay}</td>
        <td className={styles.center}>{getNightsDisplay(b)}</td>
        <td className={styles.total}>{'PHP ' + (b.total || 0).toLocaleString()}</td>

        <td onClick={function(e) { e.stopPropagation(); }}>
          <button
            className={styles.paidBtn + ' ' + (b.paid ? styles.paidYes : styles.paidNo)}
            onClick={function() { onPaid(b); }}
            type="button"
            title="Click to change payment status"
          >
            {b.paid ? 'Paid' : 'Unpaid'}
          </button>
        </td>

        <td>
          <span className={styles.statusBadge + ' ' + (STATUS_COLORS[b.status] || '')}>
            {b.status}
          </span>
        </td>

        <td onClick={function(e) { e.stopPropagation(); }}>
          <div className={styles.actionGroup}>
            <button className={styles.iconBtn} onClick={function() { onEdit(b); }} type="button" title="Edit booking">
              <IconEdit />
            </button>
            {messengerUrl && (
              <MessengerLink url={messengerUrl} className={styles.iconBtnLink} />
            )}
            <button className={styles.iconBtn + ' ' + styles.iconBtnDanger} onClick={function() { onDelete(b); }} type="button" title="Delete booking">
              <IconTrash />
            </button>
          </div>
        </td>
      </tr>

      {isExpanded && (
        <tr className={styles.expandedRow}>
          <td colSpan={10}>
            <div className={styles.expandedContent}>
              <div className={styles.expandedItem}>
                <span className={styles.expandLabel}>Guests</span>
                <span>{b.guests} pax</span>
              </div>
              <div className={styles.expandedItem}>
                <span className={styles.expandLabel}>Contact</span>
                <span>
                  {messengerUrl
                    ? <MessengerLink url={messengerUrl} label={contact} className={styles.messengerLink} />
                    : contact}
                </span>
              </div>
              <div className={styles.expandedItem}>
                <span className={styles.expandLabel}>Booked On</span>
                <span>{new Date(b.createdAt).toLocaleString('en-PH')}</span>
              </div>
              <div className={styles.expandedItem}>
                <span className={styles.expandLabel}>Special Requests</span>
                <span>{b.specialRequests || 'None'}</span>
              </div>
            </div>
          </td>
        </tr>
      )}
    </React.Fragment>
  );
};

const BookingsTable = function(props) {
  var bookings        = props.bookings;
  var onTogglePaid    = props.onTogglePaid;
  var onCancelBooking = props.onCancelBooking;
  var onEditBooking   = props.onEditBooking;

  const [filter,      setFilter]     = useState('all');
  const [search,      setSearch]     = useState('');
  const [expandedId,  setExpandedId] = useState(null);
  const [editTarget,  setEditTarget] = useState(null);
  const [modal,       setModal]      = useState({
    isOpen: false, type: 'warning', title: '', message: '', onConfirm: null,
  });

  var openModal = function(opts) {
    setModal({ isOpen: true, type: opts.type, title: opts.title, message: opts.message, onConfirm: opts.onConfirm });
  };
  var closeModal = function() {
    setModal(function(prev) { return Object.assign({}, prev, { isOpen: false, onConfirm: null }); });
  };
  var handleModalConfirm = function() {
    if (modal.onConfirm) modal.onConfirm();
    closeModal();
  };

  var handleDeleteClick = function(b) {
    openModal({
      type:    'cancel',
      title:   'Delete Booking?',
      message: 'Permanently delete the booking of ' + b.guestName + ' (' + b.id + ')? This cannot be undone.',
      onConfirm: function() {
        if (expandedId === b.id) setExpandedId(null);
        onCancelBooking(b);
      },
    });
  };

  var handlePaidClick = function(b) {
    openModal({
      type:    b.paid ? 'warning' : 'edit',
      title:   b.paid ? 'Mark as Unpaid?' : 'Mark as Paid?',
      message: b.paid
        ? b.guestName + "'s booking will be marked as unpaid."
        : b.guestName + "'s booking (PHP " + (b.total || 0).toLocaleString() + ') will be marked as paid. Please confirm.',
      onConfirm: function() { onTogglePaid(b); },
    });
  };

  var handleEditClick = function(b) { setEditTarget(b); };

  var handleEditSave = function(updated) {
    openModal({
      type:    'edit',
      title:   'Save Changes?',
      message: 'Save changes to ' + updated.guestName + "'s booking (" + updated.id + ')?',
      onConfirm: function() {
        onEditBooking(updated);
        setEditTarget(null);
      },
    });
  };

  var FILTERS = ['all', 'confirmed', 'paid', 'unpaid'];

  var filtered = bookings.filter(function(b) {
    var matchFilter =
      filter === 'all' ||
      (filter === 'paid'      &&  b.paid) ||
      (filter === 'unpaid'    && !b.paid) ||
      (filter === 'confirmed' && b.status === 'confirmed');
    var contact = b.guestContact || '';
    var matchSearch = !search ||
      b.guestName.toLowerCase().includes(search.toLowerCase()) ||
      b.id.toLowerCase().includes(search.toLowerCase()) ||
      contact.toLowerCase().includes(search.toLowerCase());
    return matchFilter && matchSearch;
  });

  return (
    <React.Fragment>
      <ConfirmModal
        isOpen={modal.isOpen}
        type={modal.type}
        title={modal.title}
        message={modal.message}
        onConfirm={handleModalConfirm}
        onCancel={closeModal}
      />

      {editTarget && (
        <EditModal
          booking={editTarget}
          onSave={handleEditSave}
          onClose={function() { setEditTarget(null); }}
        />
      )}

      <div className={styles.wrapper}>
        <div className={styles.toolbar}>
          <div className={styles.filters}>
            {FILTERS.map(function(f) {
              return (
                <button
                  key={f}
                  className={styles.filterBtn + (filter === f ? ' ' + styles.active : '')}
                  onClick={function() { setFilter(f); }}
                  type="button"
                >
                  {f.charAt(0).toUpperCase() + f.slice(1)}
                </button>
              );
            })}
          </div>
          <input
            className={styles.search}
            type="text"
            placeholder="Search name, contact, ref code..."
            value={search}
            onChange={function(e) { setSearch(e.target.value); }}
          />
        </div>

        {filtered.length === 0 ? (
          <div className={styles.empty}>
            <span>🌸</span>
            <p>No bookings found.</p>
          </div>
        ) : (
          <div className={styles.tableWrap}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Ref Code</th>
                  <th>Guest</th>
                  <th>Type</th>
                  <th>Check-in</th>
                  <th>Check-out / Last Day</th>
                  <th>Nights/Days</th>
                  <th>Total</th>
                  <th>Payment</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(function(b) {
                  return (
                    <BookingRow
                      key={b.id}
                      b={b}
                      expandedId={expandedId}
                      setExpandedId={setExpandedId}
                      onEdit={handleEditClick}
                      onDelete={handleDeleteClick}
                      onPaid={handlePaidClick}
                    />
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        <div className={styles.tableFooter}>
          {'Showing ' + filtered.length + ' of ' + bookings.length + ' bookings'}
        </div>
      </div>
    </React.Fragment>
  );
};

export default BookingsTable;
